/* eslint-disable no-console */

define(['jquery', 'core/ajax'], function ($, Ajax) {

    return {
        /**
         * Inicialización del módulo
         */
        init: function () {

          /**
             * Espera hasta que DataTables esté disponible antes de ejecutar un callback.
             *
             * @param {Function} callback Función a ejecutar cuando DataTables esté listo.
             * @returns {void}
             */
            function waitForDataTables(callback) {
                if ($.fn.DataTable) {
                    callback();
                } else {
                    setTimeout(function () {
                        waitForDataTables(callback);
                    }, 100);
                }
            }

            waitForDataTables(function () {

                const table = $('#detalleUsuariosAnioTable').DataTable({
                    data: [],
                    columns: [
                        { data: 'year' },
                        { data: 'totalusers' }
                    ],
                    dom: 'Bfrtip',
                    buttons: [
                        {
                            extend: 'excel',
                            text: 'Descargar Excel',
                            title: 'Reporte Usuarios por Año'
                        }
                    ]
                });

                Ajax.call([{
                    methodname: 'local_dashboard_v3_get_total_users',
                    args: {},
                    done: function (response) {
                        table.clear().rows.add(response).draw();
                    },
                    fail: function (error) {
                        console.error(error);
                    }
                }]);

            });

        }
    };
});